#include <iostream>  #include <vector>
using namespace std;

class Solution {
public:
        void solve(vector& edges) {
            int n = edges.size();
            vector<vector<int>> graph(n);
            bool visited[n];
            for (int i = 0; i < n; i++) {
                visited[i] = false;
            }
            int roots[n];
            for (int i = 0; i < n; i++) {
                roots[i] = i;
            }
            for (int i = 0; i < edges.size(); i += 2) {
                graph[edges[i] - 1].push_back(edges[i + 1] - 1);
                graph[edges[i + 1] - 1].push_back(edges[i] - 1);
            }
            for (int i = 0; i < n; i++) {
                if (!visited[i] && dfs(i, -1)) {
                    cout  i + 1;
                    return;
                }
            }
            cout  No cycle;
        }

        bool dfs(int node, int parent) {
            visited[node] = true;
            for (int child : graph[node]) {
                if (visited[child] && child != parent) {
                    return true;
                }
                if (!visited[child]) {
                    if (dfs(child, node)) {
                        return true;
                    }
                }
            }
            return false;
        }
};

